"use strict";async function clickedFeature(t){const e=t.layer.feature.id,n=`${mapConfig.featuresLayerDetailsUrlTemplate}${e}/`,r=await(await fetch(n)).json(),s=`
    <p>
        <strong>Tree type:</strong><br/>
        ${r.art_latein}
    </p>
    <p>
        <strong>Plantation year:</strong><br/>
        ${r.pflanzjahr}
    </p>
    <p>
        <strong>Stem circumference:</strong><br/>
        ${r.stammumfang} cm
    </p>
    <p>
        <strong>Crown diameter:</strong><br/>
        ${r.kronendurchmesser} m
    </p>
    <p>
        <strong>Address:</strong><br/>
        ${r.address}<br/>
        Hamburg, Germany
    </p>`;map.openPopup(s,t.latlng,{offset:L.point(0,-1)})}
